sys_script_include.script:
/**
 * @class AppInstallExecutor
 * @description Executes the installation related tasks.
 * @since 23/02/2026
 * @date  23/02/2026
 * @version 1.0.0
 * @author Thomas Grensemann E-Mail: <thomas.grensemann@t-systems.com>
 *
 */
class AppInstallExecutor extends global.AbstractAjaxProcessor {

	/**
	 * Executes the AppInstall scripts
	 */
    execute() {
		const APPS = DeployerConfig.getApps();

		// eslint-disable-next-line
        for (const key in APPS) {
            APPS[key]();
        }
    }
}
